INSERT INTO `v1_fb396b02c5046468fc4f60898f848d734c41dc0c36886f5391724e2bb0de2c44` VALUES (10.85, 0.0, 7, 129901, "エリコ", 1, 10142, "2024/03/31 12:00:00", 0.0, 24, 100, "訓練成功、おめでとうございます\n褒めるべき時にはしっかり褒めるのも\n教官の務めですものね。それとも、\n罵られる方が好みですか？　クスクス", "2030/12/17 14:59:59", 100);
INSERT INTO `v1_fb396b02c5046468fc4f60898f848d734c41dc0c36886f5391724e2bb0de2c44` VALUES (11.15, 0.0, 2, 129901, "エリコ", 1, 10142, "2024/03/31 12:00:00", 0.0, 24, 101, "厳しい訓練も、終わってみれば\n短く感じるものですわね。\n正直、私は暴れ足りないくらい…\nいえ、何でもありませんわ。クスクス", "2030/12/17 14:59:59", 101);
INSERT INTO `v1_fb396b02c5046468fc4f60898f848d734c41dc0c36886f5391724e2bb0de2c44` VALUES (6.4, 0.0, 5, 129901, "エリコ", 7, 10142, "2024/03/31 12:00:00", 0.0, 24, 102, "行く手を阻む忌々しい邪魔者を\n蹴散らして、見事ゴールイン…！\nまるで私とあのおかたの人生を\n象徴するような道のりでした…", "2030/12/17 14:59:59", 102);
INSERT INTO `v1_fb396b02c5046468fc4f60898f848d734c41dc0c36886f5391724e2bb0de2c44` VALUES (0.0, 0.0, 3, 129901, "エリコ", 3, 10142, "2024/03/31 12:00:00", 0.0, 24, 103, "まったくもって不甲斐ない結果です\nしかし、挽回の機会はまだありますわ\n次はゴミ虫の地位から脱却できるよう\n死力を尽くしなさい。いいですね？", "2030/12/17 14:59:59", 103);
INSERT INTO `v1_fb396b02c5046468fc4f60898f848d734c41dc0c36886f5391724e2bb0de2c44` VALUES (2.43, 0.0, 8, 129901, "エリコ", 2, 10142, "2024/03/31 12:00:00", 0.0, 24, 104, "クスクス…ああご心配なさらず\nなんとも情けない成績を残す輩には\nどんな罰が相応しいか、考えている\nだけですので…クスクスクス", "2030/12/17 14:59:59", 104);
INSERT INTO `v1_fb396b02c5046468fc4f60898f848d734c41dc0c36886f5391724e2bb0de2c44` VALUES (9.08, 0.0, 3, 129901, "エリコ", 4, 10142, "2024/03/31 12:00:00", 0.0, 24, 105, "私が教官として認められなければ、\nあのおかたを失望させてしまう…\nそれだけはあってはなりません\nあなた方も、わかっていますわね？", "2030/12/17 14:59:59", 105);
INSERT INTO `v1_fb396b02c5046468fc4f60898f848d734c41dc0c36886f5391724e2bb0de2c44` VALUES (0.0, 0.0, 6, 129901, "エリコ", 6, 10142, "2024/03/31 12:00:00", 0.0, 24, 106, "まずまずの結果ではありますが、\nこの程度で満足してもらっては\n困りますわ。エリコ班の一員として、\nより高みを目指していただきますので", "2030/12/17 14:59:59", 106);
INSERT INTO `v1_fb396b02c5046468fc4f60898f848d734c41dc0c36886f5391724e2bb0de2c44` VALUES (10.6, 0.0, 8, 129901, "エリコ", 3, 10142, "2024/03/31 12:00:00", 0.0, 24, 107, "私の指導を受けながら、この結果は…\nもっと真剣に考えねばなりませんね\nあなた方が怠けずにいるには、\nどんなしつけが必要かを…クスクス", "2030/12/17 14:59:59", 107);
INSERT INTO `v1_fb396b02c5046468fc4f60898f848d734c41dc0c36886f5391724e2bb0de2c44` VALUES (7.54, 0.0, 4, 129901, "エリコ", 6, 10142, "2024/03/31 12:00:00", 0.0, 24, 108, "ひとまず訓練をこなしたご褒美か、\n実力を出しきれたとは言えない罰か…\nみなさんにどちらを与えるべきか\n少し悩む結果ですわね", "2030/12/17 14:59:59", 108);
INSERT INTO `v1_fb396b02c5046468fc4f60898f848d734c41dc0c36886f5391724e2bb0de2c44` VALUES (11.5, 0.0, 7, 129901, "エリコ", 2, 10142, "2024/03/31 12:00:00", 0.0, 24, 109, "なかなかいい戦いぶりでしたわ\nこれもあなた方の頑張りと、何より\n優秀な教官である私の教育の賜物\nそうですわね？　クスクスクス…", "2030/12/17 14:59:59", 109);
INSERT INTO `v1_fb396b02c5046468fc4f60898f848d734c41dc0c36886f5391724e2bb0de2c44` VALUES (8.83, 0.0, 1, 129901, "エリコ", 2, 10142, "2024/03/31 12:00:00", 0.0, 24, 110, "これだけ進めたのならば合格点ですわ\nでも、もっと高みを目指したいと\n思っているのなら…さらなる訓練にも\n付き合って差し上げましょう", "2030/12/17 14:59:59", 110);
INSERT INTO `v1_fb396b02c5046468fc4f60898f848d734c41dc0c36886f5391724e2bb0de2c44` VALUES (6.68, 0.0, 2, 129901, "エリコ", 1, 10142, "2024/03/31 12:00:00", 0.0, 24, 111, "未熟で頼りなかったあなた方が、\n見違えるように成長しました\nなるほど…これこそが、教官冥利に\n尽きるという気持ちなのですね", "2030/12/17 14:59:59", 111);
INSERT INTO `v1_fb396b02c5046468fc4f60898f848d734c41dc0c36886f5391724e2bb0de2c44` VALUES (8.8, 0.0, 2, 129901, "エリコ", 6, 10142, "2024/03/31 12:00:00", 0.0, 24, 112, "まさかあなた方が、私の予想すら\n超える力を発揮するとは…驚きました\nもはやゴミ虫などではありません\n一人前の騎士として胸を張りなさい", "2030/12/17 14:59:59", 112);
INSERT INTO `v1_fb396b02c5046468fc4f60898f848d734c41dc0c36886f5391724e2bb0de2c44` VALUES (8.9, 0.0, 1, 129901, "エリコ", 2, 10142, "2024/03/31 12:00:00", 0.0, 24, 113, "クスクス、見事な働きです\nみなさんならできると信じていました\n他でもない私の指導を受けた、\nエリコ班の優秀な新兵なのですから", "2030/12/17 14:59:59", 113);
INSERT INTO `v1_fb396b02c5046468fc4f60898f848d734c41dc0c36886f5391724e2bb0de2c44` VALUES (3.7, 0.0, 5, 129901, "エリコ", 2, 10142, "2024/03/31 12:00:00", 0.0, 24, 114, "なんてすばらしい成績…！\n今日という日は『あのおかたを想い\nエリコが限界を超えた記念日』として\n歴史に刻まれることでしょう…！", "2030/12/17 14:59:59", 114);
INSERT INTO `v1_fb396b02c5046468fc4f60898f848d734c41dc0c36886f5391724e2bb0de2c44` VALUES (7.6, 0.0, 2, 129801, "マコト", 1, 10142, "2024/03/31 12:00:00", 0.0, 24, 200, "よし、いい訓練になったな\nおまえたちもよく動けてたし、\nちゃんと成長できてると思うぜ\nその調子で頑張れよっ", "2030/12/17 14:59:59", 200);
INSERT INTO `v1_fb396b02c5046468fc4f60898f848d734c41dc0c36886f5391724e2bb0de2c44` VALUES (2.25, 0.0, 1, 129801, "マコト", 2, 10142, "2024/03/31 12:00:00", 0.0, 24, 201, "ひとまずゴールおめでとう！\nでも、努力は継続してこそだからな\nおまえたちにやる気があるなら、\n何度だって付き合ってやるよ", "2030/12/17 14:59:59", 201);
INSERT INTO `v1_fb396b02c5046468fc4f60898f848d734c41dc0c36886f5391724e2bb0de2c44` VALUES (3.28, 0.0, 1, 129801, "マコト", 2, 10142, "2024/03/31 12:00:00", 0.0, 24, 202, "行軍訓練はこれにて完了！\n…なーんて思ってないよな？\n学んだことが体に染みつくまで\n地道に繰り返すのが練習ってもんさ", "2030/12/17 14:59:59", 202);
INSERT INTO `v1_fb396b02c5046468fc4f60898f848d734c41dc0c36886f5391724e2bb0de2c44` VALUES (2.98, 0.0, 1, 129801, "マコト", 4, 10142, "2024/03/31 12:00:00", 0.0, 24, 203, "みんなに無理をさせちまったか…\nでもこれで諦めることはないぜ\n次はきっとうまくいく。そう信じて\n鍛え続ければ、道は開けるはずだ！", "2030/12/17 14:59:59", 203);
INSERT INTO `v1_fb396b02c5046468fc4f60898f848d734c41dc0c36886f5391724e2bb0de2c44` VALUES (3.0, 0.0, 1, 129801, "マコト", 4, 10142, "2024/03/31 12:00:00", 0.0, 24, 204, "こいつは悔しい結果だな…\nま、反省点はいろいろあったし\nひとつずつ乗り越えていこう\nあたしたちで力を合わせて、なっ！", "2030/12/17 14:59:59", 204);
INSERT INTO `v1_fb396b02c5046468fc4f60898f848d734c41dc0c36886f5391724e2bb0de2c44` VALUES (10.3, 0.0, 2, 129801, "マコト", 1, 10142, "2024/03/31 12:00:00", 0.0, 24, 205, "おまえたちはまだ未熟な訓練兵、\n失敗を必要以上に悔やむことはねえよ\nでも実戦じゃこうはいかないからな\n次は気合を入れ直していけよっ！", "2030/12/17 14:59:59", 205);
INSERT INTO `v1_fb396b02c5046468fc4f60898f848d734c41dc0c36886f5391724e2bb0de2c44` VALUES (2.93, 0.0, 1, 129801, "マコト", 6, 10142, "2024/03/31 12:00:00", 0.0, 24, 206, "これがおまえたちの全力？\nいやいや、そんなはずはないよなっ\nおまえらならもっと強くなれる！\nあたしが言うんだ、間違いないぜ！", "2030/12/17 14:59:59", 206);
INSERT INTO `v1_fb396b02c5046468fc4f60898f848d734c41dc0c36886f5391724e2bb0de2c44` VALUES (9.3, 0.0, 1, 129801, "マコト", 3, 10142, "2024/03/31 12:00:00", 0.0, 24, 207, "おまえたちの実力を考えりゃ、\nベストを尽くせたとは言えない成績だ\nなら、次やるべきことも決まってる\n気持ちを切り替えて、鍛え直すんだ！", "2030/12/17 14:59:59", 207);
INSERT INTO `v1_fb396b02c5046468fc4f60898f848d734c41dc0c36886f5391724e2bb0de2c44` VALUES (6.9, 0.0, 1, 129801, "マコト", 4, 10142, "2024/03/31 12:00:00", 0.0, 24, 208, "まだまだ課題がある内容だったな～\n無駄な動き、判断の遅れ…\nそういうのをしっかり直していけば、\n記録ももっと伸びるはずだっ", "2030/12/17 14:59:59", 208);
INSERT INTO `v1_fb396b02c5046468fc4f60898f848d734c41dc0c36886f5391724e2bb0de2c44` VALUES (0.0, 0.0, 2, 129801, "マコト", 2, 10142, "2024/03/31 12:00:00", 0.0, 24, 209, "ここまでいけりゃ、合格点！\nむしろ、最初の頼りなさを思えば\nすげえ成長してるんじゃねえか？\n胸を張れる結果だと思うぜっ！", "2030/12/17 14:59:59", 209);
INSERT INTO `v1_fb396b02c5046468fc4f60898f848d734c41dc0c36886f5391724e2bb0de2c44` VALUES (5.95, 0.0, 2, 129801, "マコト", 1, 10142, "2024/03/31 12:00:00", 0.0, 24, 210, "なかなかハードな訓練だったけど、\nみんなしっかりついてこられたな\n地道に続けた基礎トレの成果が\n形になってる、その証だぜっ", "2030/12/17 14:59:59", 210);
INSERT INTO `v1_fb396b02c5046468fc4f60898f848d734c41dc0c36886f5391724e2bb0de2c44` VALUES (6.73, 0.0, 1, 129801, "マコト", 2, 10142, "2024/03/31 12:00:00", 0.0, 24, 211, "今回の訓練もよく頑張ったな！\nしっかり休んで次に備えろよ！\nなんつーか、教え子が成長してくのを\n見るのは楽しいもんだな…", "2030/12/17 14:59:59", 211);
INSERT INTO `v1_fb396b02c5046468fc4f60898f848d734c41dc0c36886f5391724e2bb0de2c44` VALUES (0.0, 0.0, 2, 129801, "マコト", 2, 10142, "2024/03/31 12:00:00", 0.0, 24, 212, "おまえら、すげえじゃねえか！\nこれならもう、ひよっこ新兵なんて\n言えねえな。きっと騎士団でも\n大活躍間違いなしだぜ！", "2030/12/17 14:59:59", 212);
INSERT INTO `v1_fb396b02c5046468fc4f60898f848d734c41dc0c36886f5391724e2bb0de2c44` VALUES (6.65, 0.0, 2, 129801, "マコト", 1, 10142, "2024/03/31 12:00:00", 0.0, 24, 213, "敵との戦い方、状況判断の正確さ\n何より根性…どれも最高だったぞ！\nうかうかしてたら、教官のあたしまで\n追い抜かれちまうかもな…へへっ", "2030/12/17 14:59:59", 213);
INSERT INTO `v1_fb396b02c5046468fc4f60898f848d734c41dc0c36886f5391724e2bb0de2c44` VALUES (3.05, 0.0, 1, 129801, "マコト", 6, 10142, "2024/03/31 12:00:00", 0.0, 24, 214, "あたしの指導が良かった？\nいやいや、ここまで強くなれたのは、\n他でもないおまえたち自身が努力した\nおかげだよ。改めて…おめでとうっ！", "2030/12/17 14:59:59", 214);
